const triggerData = $('Execute Workflow Trigger').first().json;
const userData = $('Get User Data').first().json;
const goalData = $('Get Goals').first().json;
const weightHistory = $('Get Weight History').all().map(i => i.json);

let totalChange = 0;
let weeklyRate = 0;
let percentProgress = 0;
let projectedDate = null;

if (weightHistory.length >= 2) {
  const latest = parseFloat(weightHistory[0].weight_kg);
  const oldest = parseFloat(weightHistory[weightHistory.length - 1].weight_kg);
  totalChange = latest - oldest;

  const latestDate = new Date(weightHistory[0].logged_at);
  const oldestDate = new Date(weightHistory[weightHistory.length - 1].logged_at);
  const weeks = (latestDate - oldestDate) / (1000 * 60 * 60 * 24 * 7);
  weeklyRate = weeks > 0 ? totalChange / weeks : 0;
}

if (goalData && goalData.target_weight && userData.weight_kg) {
  const startWeight = parseFloat(goalData.start_weight || (weightHistory.length > 0 ? weightHistory[weightHistory.length - 1].weight_kg : userData.weight_kg));
  const targetWeight = parseFloat(goalData.target_weight);
  const currentWeight = weightHistory.length > 0 ? parseFloat(weightHistory[0].weight_kg) : parseFloat(userData.weight_kg);
  const totalNeeded = startWeight - targetWeight;
  const achieved = startWeight - currentWeight;
  percentProgress = totalNeeded !== 0 ? Math.round((achieved / totalNeeded) * 100) : 0;

  if (weeklyRate !== 0) {
    const remainingKg = currentWeight - targetWeight;
    const weeksNeeded = Math.abs(remainingKg / weeklyRate);
    const projDate = new Date();
    projDate.setDate(projDate.getDate() + Math.round(weeksNeeded * 7));
    projectedDate = projDate.toISOString().split('T')[0];
  }
}

return [{
  json: {
    userId: triggerData.userId,
    chatId: triggerData.chatId,
    firstName: userData.first_name,
    currentWeight: weightHistory.length > 0 ? weightHistory[0].weight_kg : userData.weight_kg,
    targetWeight: goalData ? goalData.target_weight : null,
    totalChange: Math.round(totalChange * 100) / 100,
    weeklyRate: Math.round(weeklyRate * 100) / 100,
    percentProgress,
    projectedDate
  }
}];

const data = $input.first().json;

const changeSymbol = data.totalChange > 0 ? '+' : '';
const trendEmoji = data.totalChange < 0 ? '📉' : data.totalChange > 0 ? '📈' : '➡️';

let message = '📊 *Reporte de Progreso*\n\nHola ' + data.firstName + '!\n\n';
message += '⚖️ Peso actual: *' + data.currentWeight + ' kg*\n';

if (data.targetWeight) {
  message += '🎯 Peso objetivo: *' + data.targetWeight + ' kg*\n';
}

message += trendEmoji + ' Cambio total: *' + changeSymbol + data.totalChange + ' kg*\n';
message += '📅 Tasa semanal: *' + (data.weeklyRate > 0 ? '+' : '') + data.weeklyRate + ' kg/semana*\n';

if (data.percentProgress !== undefined) {
  message += '✅ Progreso hacia meta: *' + data.percentProgress + '%*\n';
}

if (data.projectedDate) {
  message += '🗓️ Fecha estimada de meta: *' + data.projectedDate + '*\n';
}

message += '\n¡Sigue así! Cada paso cuenta. 💪';

return [{ json: { chatId: data.chatId, message } }];

